local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxFightIdleCtrl:LxBaseCtrl
local LxFightIdleCtrl = classX("LxFightIdleCtrl", LxBaseCtrl)

function LxFightIdleCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

    self._FightIdleMgr = require("LApp.gameplay.FightIdle.LxFightIdleMgr"):new()
    self._FightIdleMgr:Initialize()

end

function LxFightIdleCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end
--- 获取当前显示的章节奖励
function LxFightIdleCtrl:GetCurShowChapterReward()
    local FightIdleM = ModuleCenter.FightIdle
    local curLvId = FightIdleM:GetCompleteMission()
    local sortRewardList = self:GetSortInsRewardRef()
    for _, v in ipairs(sortRewardList) do
        local isCanGet = self:CheckInsRewardIsCanGet(v.refId)
        if isCanGet or v.refId > curLvId then
            return v
        end
    end
    return sortRewardList[1]
end
--- 获取排序好的 关卡奖励配置表
function LxFightIdleCtrl:GetSortInsRewardRef()
    local sortList = {}
    local InsRewardRefList = GameTable.InsRewardRef
    for _, v in pairs(InsRewardRefList) do
        table.insert(sortList, v)
    end
    table.sort(sortList, function(a, b) return a.sort < b.sort end)
    return sortList
end

--- 获取关卡ref 不传就返回当前已通关的关卡，要是没有通关过 就返回第一关
function LxFightIdleCtrl:GetMissionRef(refId)
    local curLvId = ModuleCenter.FightIdle:GetCompleteMission()
    if curLvId == 0 then
        curLvId = GameTable.InsWorldRef[1].firstInstanceId
    end
    refId = (refId and refId > 0) and refId or curLvId
    return GameTable.InsMissionRef[refId]
end
--- 获取当前进行中的关卡配置
function LxFightIdleCtrl:GetCurMissionRef()
    local completeMissionId = ModuleCenter.FightIdle:GetCompleteMission()
    local curLvId = 0
    if completeMissionId == 0 then
        curLvId = GameTable.InsWorldRef[1].firstInstanceId
    else
        local ref = GameTable.InsMissionRef[completeMissionId]
        if ref.NextinstanceId > 0 then
            curLvId = ref.NextinstanceId
        else
            local worldRef = GameTable.InsWorldRef[ref.belongChapterId + 1]
            if not worldRef then    -- 最后一关了
                curLvId = completeMissionId
            else
                curLvId = worldRef.firstInstanceId
            end
        end
    end
    return GameTable.InsMissionRef[curLvId]
end
--- @return V_InsWorldRef 不传refId 就返回 当前关卡所在的章节
function LxFightIdleCtrl:GetChapterRef(refId)
    if not refId then
        local curLvId = ModuleCenter.FightIdle:GetCompleteMission()
        if curLvId == 0 then
            return GameTable.InsWorldRef[1]
        else
            local missionRef = self:GetMissionRef()
            return GameTable.InsWorldRef[missionRef.belongChapterId]
        end
    else
        return GameTable.InsWorldRef[refId]
    end
end
function LxFightIdleCtrl:ChangeFightIdleMap(loadParams)
    local ref = self:GetChapterRef()
    local mapName = ref.mainSceneId
    loadParams = loadParams or {loadUIName = UiNames.Interlude}
    MgrCenter.LevelMgr:LoadLevel(LevelNames.FightIdle, {mapName = mapName}, loadParams)
end
--- 计算章节进度条的值
function LxFightIdleCtrl:GetChapterSliderValue()
    local ref = self:GetChapterRef()
    local curValue = ref.refId - 1
    local maxValue = #GameTable.InsWorldRef - 1
    return curValue / maxValue
end


--- 获取挂机特权 奖励展示
function LxFightIdleCtrl:GetPrivilegeReward()
    local ref = GameTable.MonthlyCardRef[3]
    local showList = {} --- reward 道具， type 0 基础奖励 1 每日奖励 2 每周奖励
    for _, v in ipairs(ref.rewardBase) do   --- 基础奖励
        local _t = {}
        _t.reward = v
        _t.type = 0
        table.insert(showList, _t)
    end
    if ref.rewardDay then
        for _, v in ipairs(ref.rewardDay) do   --- 每日奖励
        local _t = {}
            _t.reward = v
            _t.type = 1
            _t.res = "shop_sign2"
            _t.lbl = I18nText(3521)
            table.insert(showList, _t)
        end
    end
    if ref.rewardWeek then
        for _, v in ipairs(ref.rewardWeek) do   --- 每周奖励
        local _t = {}
            _t.reward = v
            _t.type = 1
            _t.res = "shop_sign3"
            _t.lbl = I18nText(3522)
            table.insert(showList, _t)
        end
    end
    return showList
end
--- 获取当前关卡挂机的掉落概率
function LxFightIdleCtrl:GetDropProbability()
    local showList = {}
    local ref = self:GetMissionRef()
    local dropRefList = GameTable.DropItemRef
    if table.isempty(ref.timeRewardRand) then
        return showList
    end
    for _, v in ipairs(ref.timeRewardRand) do
        local dropRef = dropRefList[v]
        if dropRef then
            for _, v2 in ipairs(dropRef.values) do
                table.insert(showList, v2)
            end
        end
    end
    return showList
end
--- 章节奖励配置
function LxFightIdleCtrl:GetChapterShowReward()
    local ref = GameTable.InsRewardRef
    local missionRef = self:GetCurMissionRef()
    local showList = {} --- 当前展示的章节奖励列表 有可领取的章节 > 当前章节
    local _sortT = {}
    local curReward --- 当前进度奖励
    local curChapterId = -1
    for _, v in pairs(ref) do
        table.insert(_sortT, v)
    end
    table.sort(_sortT, function(a, b) return a.sort < b.sort end)
    for i, v in ipairs(_sortT) do
        if curChapterId > 0 and curChapterId ~= v.insWorld then
            break
        end
        local isCurChapter = v.insWorld == missionRef.belongChapterId
        local isCanGet = self:CheckInsRewardIsCanGet(v.refId)
        if isCurChapter or isCanGet or curChapterId == v.insWorld then
            curChapterId = v.insWorld
            local _t = {}
            local nextCfg = _sortT[i + 1]
            _t.cfg = v
            _t.nextLv = (nextCfg and nextCfg.insWorld == curChapterId) and nextCfg.refId or -1
            if missionRef.refId >= v.refId then
                curReward = _t
            end
            table.insert(showList, _t)
        end
    end
    if not curReward then
        curReward = showList[1]
    end
    return showList, curReward
end
--- 关卡奖励是否可领取
--- @param refId number InsRewardRef - refId
function LxFightIdleCtrl:CheckInsRewardIsCanGet(refId)
    local rewards = ModuleCenter.FightIdle:GetChapterRewards()
    local isReceive = self:CheckInsRewardIsReceive(refId)
    return rewards[refId] and not isReceive
end
--- 是否已领取
function LxFightIdleCtrl:CheckInsRewardIsReceive(refId)
    local receives = ModuleCenter.FightIdle:GetReceives()
    return receives[refId] ~= nil
end
--- 根据章节获取 对应章节的所有据点配置
function LxFightIdleCtrl:GetChapterMissionList(chapterId)
    local missionList = {}
    local sortMissionList = self:GetSortMissionList()
    local chapterRef = GameTable.InsWorldRef[chapterId]
    local firstRef = GameTable.InsMissionRef[chapterRef.firstInstanceId]
    for i = firstRef.num, #sortMissionList do
        local ref = sortMissionList[i]
        if ref.belongChapterId ~= chapterId then
            break
        end
        table.insert(missionList, ref)
    end
    return missionList
end
--- 根据关卡数 排序好的据点配置
function LxFightIdleCtrl:GetSortMissionList()
    if self._sortMissionList then
        return self._sortMissionList
    end
    self._sortMissionList = {}
    local missionList = GameTable.InsMissionRef
    for _, v in pairs(missionList) do
        table.insert(self._sortMissionList, v)
    end
    table.sort(self._sortMissionList, function(a, b) return a.num < b.num end)
    return self._sortMissionList
end

function LxFightIdleCtrl:GoToChallenge(isBattleWithoutWin)
    local completeMissionId = ModuleCenter.FightIdle:GetCompleteMission()
    local misRef = self:GetMissionRef(completeMissionId)
    local chapterRef = GameTable.InsWorldRef[misRef.belongChapterId]
    if chapterRef.NextChapterId < 0 then    -- 通关
        return
    end
    local ref = self:GetCurMissionRef()
    local sceneId = ref.sceneId
    local sceneRef = GameTable.BattleSceneRef[sceneId]
    local mapName = sceneRef and sceneRef.name or ""
    if string.isempty(mapName) then
        mapName = "Battle003"
    end
    local jParameter = CJSON.encode({refId = ref.refId})
    local config = {
        monsterRefId = ref.monster,
        mapName = mapName,
        battleType = BattleType.Adventure,
        index = 1,
        backLevelName = LevelNames.FightIdle,
        params = {jParameter = jParameter },
        refId = ref.refId
        --uiDataForExitBattle = {{name = ref.nameWorld}},
    }
    if isBattleWithoutWin then
        CtrlCenter.Battle:GotoSilenceBattle(config)
    else
        CtrlCenter.Battle:GotoFormation(config)
    end

end


function LxFightIdleCtrl:GetFightIdleMgr()
    return self._FightIdleMgr
end
function LxFightIdleCtrl:GetFightIdleDataMgr()
    return self._FightIdleMgr:GetFightIdleDataMgr()
end
function LxFightIdleCtrl:StartFightIdle(mapTrans)
    local curRef = self:GetCurMissionRef()
    local FightIdleDataMgr = self._FightIdleMgr:GetFightIdleDataMgr()
    --据点列表,当前据点，和上一个据点
    local missionList = {curRef}
    if curRef.sort > 1 then
        local refList = self:GetChapterMissionList(curRef.belongChapterId)
        table.insert(missionList, refList[curRef.sort - 1])
    end
    local mainSceneMonId1 = curRef.mainSceneMonId1
    local normalMonList = FightIdleDataMgr:ParseIntParam_Semicolon(mainSceneMonId1)

    local mainSceneMonId2 = curRef.mainSceneMonId2
    local leaderMonList = FightIdleDataMgr:ParseIntParam_Semicolon(mainSceneMonId2)

    local mainSceneMonId3 = curRef.mainSceneMonId3
    local bossMonList = FightIdleDataMgr:ParseIntParam_Semicolon(mainSceneMonId3)
    --- 怪物列表
    local monList = {
        [LFightIdleConst.MON_QUALITY_NONE] = normalMonList,
        [LFightIdleConst.MON_QUALITY_LEADER] = leaderMonList,
        [LFightIdleConst.MON_QUALITY_BOSS] = bossMonList,
    }
    self._FightIdleMgr:StartFightIdle(mapTrans, curRef.belongChapterId, curRef.refId, "FightIdle001", monList, 0, missionList)
end

function LxFightIdleCtrl:ClearFightIdleMgr()
    self._FightIdleMgr:Clear(true)
end
function LxFightIdleCtrl:SetGuideReady(ready)
    self._guideReady = ready
end
function LxFightIdleCtrl:IsGuideReady()
