end
--- 主线推图红点
function LxFightIdleCtrl:CheckFightIdleAllRed()
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Ins)
    if not isOpen then
        return false
    end
    local rewardList, curReward = self:GetChapterShowReward()
    for _, v in ipairs(rewardList) do
        local isCanGet = self:CheckInsRewardIsCanGet(v.cfg.refId)
        if isCanGet then
            return true
        end
    end
    return false
end
return LxFightIdleCtrl